import * as Phaser from 'phaser'
import { SPRITESHEET_KEY, TEXTURES, COLORS } from '../constants'

export class BootScene extends Phaser.Scene {
	constructor() {
		super({ key: 'BootScene' })
	}

	async create(): Promise<void> {
		const images = this.registry.get('images') as {
			spritesheet: HTMLImageElement
		}

		if (images) {
			// Register spritesheet (640×160, 8 cols × 2 rows, 80×80 per frame)
			if (!this.textures.exists(SPRITESHEET_KEY)) {
				this.textures.addSpriteSheet(SPRITESHEET_KEY, images.spritesheet, {
					frameWidth: 80,
					frameHeight: 80,
				})
			}
		}

		// Generate procedural textures
		this.generateBackground()
		this.generateParticleCircle()
		this.generateParticleStar()

		// Wait for Luckiest Guy font to load before starting game
		try {
			const fontLoadPromise = document.fonts.load('bold 20px "Luckiest Guy"')
			const timeoutPromise = new Promise(resolve => setTimeout(resolve, 2000))
			await Promise.race([fontLoadPromise, timeoutPromise])
			await document.fonts.ready
		} catch {
			// Font might already be loaded or fail to load, continue anyway
		}

		// Transition to GameScene (guard against scene destroyed during await)
		if (this.scene?.manager) {
			this.scene.start('GameScene')
		}
	}

	private generateBackground(): void {
		if (this.textures.exists(TEXTURES.BACKGROUND)) return

		const boardSize = this.registry.get('boardSize') || 20
		const cellSize = this.registry.get('cellSize') || 20
		const size = boardSize * cellSize

		const gfx = this.make.graphics({ x: 0, y: 0 })
		for (let row = 0; row < boardSize; row++) {
			for (let col = 0; col < boardSize; col++) {
				const color =
					(row + col) % 2 === 0 ? COLORS.GRASS_LIGHT : COLORS.GRASS_DARK
				gfx.fillStyle(color, 1)
				gfx.fillRect(col * cellSize, row * cellSize, cellSize, cellSize)
			}
		}
		gfx.generateTexture(TEXTURES.BACKGROUND, size, size)
		gfx.destroy()
	}

	private generateParticleCircle(): void {
		if (this.textures.exists(TEXTURES.PARTICLE_CIRCLE)) return

		const gfx = this.make.graphics({ x: 0, y: 0 })
		gfx.fillStyle(0xffffff, 1)
		gfx.fillCircle(8, 8, 8)
		gfx.generateTexture(TEXTURES.PARTICLE_CIRCLE, 16, 16)
		gfx.destroy()
	}

	private generateParticleStar(): void {
		if (this.textures.exists(TEXTURES.PARTICLE_STAR)) return

		const gfx = this.make.graphics({ x: 0, y: 0 })
		const cx = 8
		const cy = 8
		const outerR = 8
		const innerR = 3
		const points = 5

		gfx.fillStyle(0xffffff, 1)
		gfx.beginPath()
		for (let i = 0; i < points * 2; i++) {
			const r = i % 2 === 0 ? outerR : innerR
			const angle = (Math.PI * i) / points - Math.PI / 2
			const x = cx + r * Math.cos(angle)
			const y = cy + r * Math.sin(angle)
			if (i === 0) {
				gfx.moveTo(x, y)
			} else {
				gfx.lineTo(x, y)
			}
		}
		gfx.closePath()
		gfx.fillPath()
		gfx.generateTexture(TEXTURES.PARTICLE_STAR, 16, 16)
		gfx.destroy()
	}
}
