export interface Position {
	x: number
	y: number
}

export type Direction = 'UP' | 'DOWN' | 'LEFT' | 'RIGHT'

export interface Food {
	position: Position
	points: number
	type:
		| 'apple'
		| 'banana'
		| 'cherries'
		| 'grapes'
		| 'mango'
		| 'pear'
		| 'watermelon'
		| 'kiwi'
		| 'boost'
		| 'diet'
}

export interface FoodType {
	type:
		| 'apple'
		| 'banana'
		| 'cherries'
		| 'grapes'
		| 'mango'
		| 'pear'
		| 'watermelon'
		| 'kiwi'
		| 'boost'
		| 'diet'
	points: number
	specialEffect?: 'boost' | 'diet'
	rarity?: number // 0-1, where 1 is most common
}

export const FOOD_TYPES: FoodType[] = [
	{ type: 'apple', points: 5, rarity: 0.18 },
	{ type: 'banana', points: 10, rarity: 0.14 },
	{ type: 'kiwi', points: 10, rarity: 0.12 },
	{ type: 'cherries', points: 15, rarity: 0.1 },
	{ type: 'pear', points: 15, rarity: 0.1 },
	{ type: 'mango', points: 20, rarity: 0.08 },
	{ type: 'grapes', points: 25, rarity: 0.08 },
	{ type: 'watermelon', points: 35, rarity: 0.05 },
	{ type: 'boost', points: 5, specialEffect: 'boost', rarity: 0.05 },
	{ type: 'diet', points: 0, specialEffect: 'diet', rarity: 0.05 },
]

export interface GameState {
	snake: Position[]
	food: Food
	direction: Direction
	nextDirection: Direction
	score: number
	lives: number
	gameStarted: boolean
	gamePaused: boolean
	gameOver: boolean
	speed: number
}

export interface SnakeGameProps {
	images: {
		spritesheet: HTMLImageElement
	}
	onScoreUpdate: (score: number) => void
	onLivesUpdate: (lives: number) => void
	onGameOver: () => void
	isPaused: boolean
	boardSize?: number
	cellSize?: number
	initialScore?: number
	initialFoodEaten?: number
}
