import React, { useEffect, useRef, useState } from 'react'
import * as Phaser from 'phaser'
import { BootScene } from './scenes/BootScene'
import { GameScene } from './scenes/GameScene'
import { SnakeGameProps } from './types'
import { snakeAudio } from './utils/audioManager'
import { hapticManager } from '../utils/hapticManager'
import { DEFAULT_BOARD_SIZE, DEFAULT_CELL_SIZE, HUD_HEIGHT } from './constants'

const SnakeGame: React.FC<SnakeGameProps> = ({
	images,
	onScoreUpdate,
	onGameOver,
	isPaused,
	boardSize = DEFAULT_BOARD_SIZE,
	cellSize = DEFAULT_CELL_SIZE,
	initialScore = 0,
	initialFoodEaten = 0,
}) => {
	const containerRef = useRef<HTMLDivElement>(null)
	const gameRef = useRef<Phaser.Game | null>(null)

	// Use refs to always hold the latest callbacks without triggering re-creation
	const onScoreUpdateRef = useRef(onScoreUpdate)
	const onGameOverRef = useRef(onGameOver)
	onScoreUpdateRef.current = onScoreUpdate
	onGameOverRef.current = onGameOver

	const canvasSize = boardSize * cellSize
	const totalHeight = canvasSize + HUD_HEIGHT

	// Boost state for CSS border
	const [boostActive, setBoostActive] = useState(false)

	// Create Phaser game once on mount
	useEffect(() => {
		if (!containerRef.current || gameRef.current) return

		snakeAudio.init()
		hapticManager.init()

		const config: Phaser.Types.Core.GameConfig = {
			type: Phaser.AUTO,
			parent: containerRef.current,
			width: canvasSize,
			height: totalHeight,
			backgroundColor: '#000000',
			scene: [BootScene, GameScene],
			scale: {
				mode: Phaser.Scale.NONE,
			},
			render: {
				pixelArt: false,
				antialias: true,
			},
		}

		gameRef.current = new Phaser.Game(config)

		// Pass data to Phaser via registry
		// Callbacks use stable wrapper functions that read from refs
		gameRef.current.registry.set('images', images)
		gameRef.current.registry.set('onScoreUpdate', (score: number) =>
			onScoreUpdateRef.current(score)
		)
		gameRef.current.registry.set('onGameOver', () => onGameOverRef.current())
		gameRef.current.registry.set('onBoostChange', (active: boolean) => {
			setBoostActive(active)
		})
		gameRef.current.registry.set('audioManager', snakeAudio)
		gameRef.current.registry.set('boardSize', boardSize)
		gameRef.current.registry.set('cellSize', cellSize)
		gameRef.current.registry.set('isPaused', isPaused)
		gameRef.current.registry.set('initialScore', initialScore)
		gameRef.current.registry.set('initialFoodEaten', initialFoodEaten)

		return () => {
			if (gameRef.current) {
				gameRef.current.destroy(true)
				gameRef.current = null
			}
			snakeAudio.dispose()
		}
		// Only depend on stable values — NOT callbacks
		// eslint-disable-next-line react-hooks/exhaustive-deps
	}, [images, boardSize, cellSize, canvasSize, totalHeight])

	// Sync pause state from React to Phaser
	useEffect(() => {
		if (gameRef.current) {
			gameRef.current.registry.set('isPaused', isPaused)
		}
	}, [isPaused])

	return (
		<div
			ref={containerRef}
			className={`game-snake-container${boostActive ? ' game-snake-container-boost' : ''}`}
			style={{
				width: canvasSize,
				height: totalHeight,
			}}
		/>
	)
}

export default SnakeGame
