import * as Phaser from 'phaser'
import { Position, Direction, Food, FOOD_TYPES } from '../types'
import { SnakeAudioManager } from '../utils/audioManager'
import { hapticManager } from '../../utils/hapticManager'
import {
	SPRITESHEET_KEY,
	SPRITE_FRAMES,
	TEXTURES,
	COLORS,
	FOOD_PARTICLE_TINTS,
	INITIAL_SPEED,
	MIN_SPEED,
	SPEED_DECREASE,
	SPEED_THRESHOLD,
	BOOST_DURATION,
	BOOST_MULTIPLIER,
	DIET_SHRINK,
	HUD_HEIGHT,
} from '../constants'

// Map food type to spritesheet frame index
const FOOD_FRAME_MAP: Record<string, number> = {
	apple: SPRITE_FRAMES.APPLE,
	banana: SPRITE_FRAMES.BANANA,
	cherries: SPRITE_FRAMES.CHERRIES,
	grapes: SPRITE_FRAMES.GRAPES,
	mango: SPRITE_FRAMES.MANGO,
	pear: SPRITE_FRAMES.PEAR,
	watermelon: SPRITE_FRAMES.WATERMELON,
	kiwi: SPRITE_FRAMES.KIWI,
	boost: SPRITE_FRAMES.BOOST,
	diet: SPRITE_FRAMES.DIET,
}

// Map direction to head spritesheet frame index
const HEAD_FRAME_MAP: Record<Direction, number> = {
	UP: SPRITE_FRAMES.HEAD_UP,
	DOWN: SPRITE_FRAMES.HEAD_DOWN,
	LEFT: SPRITE_FRAMES.HEAD_LEFT,
	RIGHT: SPRITE_FRAMES.HEAD_RIGHT,
}

export class GameScene extends Phaser.Scene {
	// Board config
	private boardSize!: number
	private cellSize!: number
	private canvasSize!: number
	private gameOffsetY!: number

	// Snake state
	private snake: Position[] = []
	private direction: Direction = 'RIGHT'
	private nextDirection: Direction = 'RIGHT'
	private speed: number = INITIAL_SPEED
	private moveTimer: number = 0
	private currentScore: number = 0
	private hasCollided: boolean = false

	// Boost state
	private boostActive: boolean = false
	private boostTimeRemaining: number = 0
	private boostMultiplier: number = 1

	// Food state
	private food!: Food
	private foodEaten: number = 0

	// Accumulated values from previous lives
	private initialScore: number = 0
	private initialFoodEaten: number = 0

	// Callbacks
	private onScoreUpdate!: (score: number) => void
	private onGameOver!: () => void
	private onBoostChange!: (active: boolean, seconds: string) => void

	// Audio
	private audioManager!: SnakeAudioManager

	// Game objects
	private backgroundImage!: Phaser.GameObjects.Image
	private headSprite!: Phaser.GameObjects.Image
	private bodySprites: Phaser.GameObjects.Image[] = []
	private foodSprite!: Phaser.GameObjects.Image
	private foodGlow!: Phaser.GameObjects.Graphics

	// HUD elements
	private hudBg!: Phaser.GameObjects.Graphics
	private hudScoreText!: Phaser.GameObjects.Text
	private hudFoodText!: Phaser.GameObjects.Text
	private hudBoostText!: Phaser.GameObjects.Text

	// Particle emitters
	private eatEmitter!: Phaser.GameObjects.Particles.ParticleEmitter
	private deathEmitter!: Phaser.GameObjects.Particles.ParticleEmitter
	private dietEmitter!: Phaser.GameObjects.Particles.ParticleEmitter
	private boostSparkleEmitter!: Phaser.GameObjects.Particles.ParticleEmitter

	// Input handler reference for cleanup
	private keydownHandler!: (e: KeyboardEvent) => void

	// Food idle animation tween
	private foodIdleTween: Phaser.Tweens.Tween | null = null
	private foodGlowTween: Phaser.Tweens.Tween | null = null

	constructor() {
		super({ key: 'GameScene' })
	}

	// ─── Cell-to-pixel helpers (apply gameOffsetY to Y) ────────

	private cellPx(cellX: number): number {
		return cellX * this.cellSize + this.cellSize / 2
	}

	private cellPy(cellY: number): number {
		return cellY * this.cellSize + this.cellSize / 2 + this.gameOffsetY
	}

	// ─── Lifecycle ─────────────────────────────────────────────

	create(): void {
		// Get config from registry
		this.boardSize = this.registry.get('boardSize') || 20
		this.cellSize = this.registry.get('cellSize') || 20
		this.canvasSize = this.boardSize * this.cellSize
		this.gameOffsetY = HUD_HEIGHT

		// Get callbacks
		this.onScoreUpdate = this.registry.get('onScoreUpdate') || (() => {})
		this.onGameOver = this.registry.get('onGameOver') || (() => {})
		this.onBoostChange = this.registry.get('onBoostChange') || (() => {})
		this.audioManager = this.registry.get('audioManager')

		// Get accumulated values from previous lives
		this.initialScore = this.registry.get('initialScore') || 0
		this.initialFoodEaten = this.registry.get('initialFoodEaten') || 0

		// Reset state
		this.snake = [{ x: 10, y: 10 }]
		this.direction = 'RIGHT'
		this.nextDirection = 'RIGHT'
		this.speed = INITIAL_SPEED
		this.moveTimer = 0
		this.currentScore = 0
		this.hasCollided = false
		this.boostActive = false
		this.boostTimeRemaining = 0
		this.boostMultiplier = 1
		this.foodEaten = 0
		this.bodySprites = []

		// Draw background (offset down by HUD)
		this.backgroundImage = this.add
			.image(
				this.canvasSize / 2,
				this.gameOffsetY + this.canvasSize / 2,
				TEXTURES.BACKGROUND
			)
			.setDisplaySize(this.canvasSize, this.canvasSize)

		// Setup food glow (drawn under food)
		this.foodGlow = this.add.graphics()

		// Spawn initial food
		this.food = this.getRandomFood()
		this.foodSprite = this.add
			.image(
				this.cellPx(this.food.position.x),
				this.cellPy(this.food.position.y),
				SPRITESHEET_KEY,
				this.getFoodFrame(this.food.type)
			)
			.setDisplaySize(this.cellSize, this.cellSize)
		this.spawnFoodAnimation()

		// Create snake head
		this.headSprite = this.add
			.image(
				this.cellPx(this.snake[0].x),
				this.cellPy(this.snake[0].y),
				SPRITESHEET_KEY,
				HEAD_FRAME_MAP[this.direction]
			)
			.setDisplaySize(this.cellSize, this.cellSize)

		// Setup HUD (draws at y=0, above the game area)
		this.setupHUD()

		// Setup particle emitters
		this.setupParticles()

		// Setup input
		this.setupInput()

		// Listen for pause changes
		this.registry.events.on(
			'changedata-isPaused',
			(_parent: unknown, value: boolean) => {
				if (value) {
					this.scene.pause()
				} else {
					this.scene.resume()
					this.moveTimer = 0 // Reset to prevent catch-up moves
				}
			}
		)

		// Cleanup on scene shutdown/destroy
		this.events.on('shutdown', () => this.cleanup())
		this.events.on('destroy', () => this.cleanup())
	}

	update(_time: number, delta: number): void {
		if (this.hasCollided) return

		// Accumulate time and move snake when threshold reached
		this.moveTimer += delta
		if (this.moveTimer >= this.speed) {
			this.moveTimer -= this.speed
			this.moveSnake()
		}

		// Tick down boost timer
		if (this.boostActive) {
			this.boostTimeRemaining -= delta
			if (this.boostTimeRemaining <= 0) {
				this.deactivateBoost()
			} else {
				this.updateBoostDisplay()
			}
		}
	}

	// ─── Core Game Logic ───────────────────────────────────────

	private moveSnake(): void {
		// Apply queued direction
		this.direction = this.nextDirection

		const head = { ...this.snake[0] }

		// Move head
		switch (this.direction) {
			case 'UP':
				head.y -= 1
				break
			case 'DOWN':
				head.y += 1
				break
			case 'LEFT':
				head.x -= 1
				break
			case 'RIGHT':
				head.x += 1
				break
		}

		// Toroidal wrapping
		if (head.x < 0) head.x = this.boardSize - 1
		if (head.x >= this.boardSize) head.x = 0
		if (head.y < 0) head.y = this.boardSize - 1
		if (head.y >= this.boardSize) head.y = 0

		// Self-collision check
		if (this.snake.some(seg => seg.x === head.x && seg.y === head.y)) {
			if (!this.hasCollided) {
				this.hasCollided = true
				this.handleDeath()
			}
			return
		}

		// Add new head
		this.snake.unshift(head)

		// Play movement sound
		this.audioManager?.playMovement()

		// Check food collision
		if (head.x === this.food.position.x && head.y === this.food.position.y) {
			this.eatFood()
		} else {
			// Remove tail
			this.snake.pop()
		}

		// Update visual positions
		this.updateSnakeVisuals()
	}

	private eatFood(): void {
		const foodType = FOOD_TYPES.find(f => f.type === this.food.type)
		const foodPixelX = this.cellPx(this.food.position.x)
		const foodPixelY = this.cellPy(this.food.position.y)

		if (foodType?.specialEffect === 'boost') {
			this.activateBoost()
			this.audioManager?.playEatBoost()
			hapticManager.perfectHit()
		} else if (foodType?.specialEffect === 'diet' && this.snake.length > 1) {
			this.dietShrink()
			this.audioManager?.playEatDiet()
			hapticManager.goodHit()
		} else {
			this.audioManager?.playEatFood()
			hapticManager.goodHit()
		}

		// Track food eaten
		this.foodEaten++

		// Calculate score
		const baseScore = this.food.points
		const actualScore = baseScore * this.boostMultiplier
		this.currentScore += actualScore

		// Send incremental score to parent
		this.onScoreUpdate(actualScore)

		// Update HUD
		this.updateHUD()

		// Show score popup
		if (actualScore > 0) {
			this.showScorePopup(foodPixelX, foodPixelY, actualScore)
		}

		// Particle burst at food position
		this.spawnEatParticles(foodPixelX, foodPixelY, this.food.type)

		// Speed increase every SPEED_THRESHOLD points
		if (this.currentScore % SPEED_THRESHOLD === 0 && this.currentScore > 0) {
			this.speed = Math.max(MIN_SPEED, this.speed - SPEED_DECREASE)
			this.audioManager?.playSpeedUp()
			hapticManager.comboMilestone()
		}

		// Spawn new food
		this.food = this.getRandomFood()
		this.updateFoodVisual()
	}

	private activateBoost(): void {
		this.boostActive = true
		this.boostTimeRemaining = BOOST_DURATION
		this.boostMultiplier = BOOST_MULTIPLIER
		this.updateBoostDisplay()

		// Sparkle emitter along border
		if (this.boostSparkleEmitter) {
			this.boostSparkleEmitter.start()
		}
	}

	private deactivateBoost(): void {
		this.boostActive = false
		this.boostTimeRemaining = 0
		this.boostMultiplier = 1
		this.onBoostChange(false, '0')
		this.hudBoostText.setVisible(false)

		if (this.boostSparkleEmitter) {
			this.boostSparkleEmitter.stop()
		}
	}

	private updateBoostDisplay(): void {
		const seconds = (this.boostTimeRemaining / 1000).toFixed(1)
		this.onBoostChange(true, seconds)
		this.hudBoostText.setText(`⚡ ${seconds}s`).setVisible(true)
	}

	private dietShrink(): void {
		const segmentsToRemove = Math.min(DIET_SHRINK, this.snake.length - 1)
		for (let i = 0; i < segmentsToRemove; i++) {
			const removed = this.snake.pop()
			if (removed) {
				// Green puff at removed segment
				this.spawnDietParticles(this.cellPx(removed.x), this.cellPy(removed.y))
			}
		}
		// Clean up excess body sprites
		this.syncBodySprites()
	}

	private handleDeath(): void {
		this.audioManager?.playGameOver()
		hapticManager.miss()

		const headX = this.cellPx(this.snake[0].x)
		const headY = this.cellPy(this.snake[0].y)

		// Red screen flash (covers game area only, not HUD)
		const flash = this.add
			.rectangle(
				this.canvasSize / 2,
				this.gameOffsetY + this.canvasSize / 2,
				this.canvasSize,
				this.canvasSize,
				COLORS.DEATH_FLASH,
				0.5
			)
			.setDepth(50)

		this.tweens.add({
			targets: flash,
			alpha: 0,
			duration: 400,
			ease: 'Quad.easeOut',
			onComplete: () => flash.destroy(),
		})

		// Camera shake
		this.cameras.main.shake(300, 0.015)

		// Radial particle burst at head
		if (this.deathEmitter) {
			this.deathEmitter.emitParticleAt(headX, headY, 20)
		}

		// Delay game over callback slightly for death effect to play
		this.time.delayedCall(350, () => {
			this.onGameOver()
		})
	}

	// ─── Food Helpers ──────────────────────────────────────────

	private getRandomPosition(): Position {
		let pos: Position
		do {
			pos = {
				x: Math.floor(Math.random() * this.boardSize),
				y: Math.floor(Math.random() * this.boardSize),
			}
		// eslint-disable-next-line no-loop-func
	} while (this.snake.some(seg => seg.x === pos.x && seg.y === pos.y))
		return pos
	}

	private getRandomFood(): Food {
		const totalWeight = FOOD_TYPES.reduce((sum, f) => sum + (f.rarity || 0), 0)
		let random = Math.random() * totalWeight

		let selected = FOOD_TYPES[0]
		for (const ft of FOOD_TYPES) {
			random -= ft.rarity || 0
			if (random <= 0) {
				selected = ft
				break
			}
		}

		return {
			position: this.getRandomPosition(),
			points: selected.points,
			type: selected.type,
		}
	}

	private getFoodFrame(type: string): number {
		return FOOD_FRAME_MAP[type] ?? SPRITE_FRAMES.APPLE
	}

	// ─── Visual Updates ────────────────────────────────────────

	private updateSnakeVisuals(): void {
		// Update head position and texture
		const headPos = this.snake[0]
		this.headSprite.setPosition(this.cellPx(headPos.x), this.cellPy(headPos.y))
		this.headSprite.setTexture(SPRITESHEET_KEY, HEAD_FRAME_MAP[this.direction])

		// Sync body sprites count
		this.syncBodySprites()

		// Update body positions and frames (BODY for middle, TAIL for last)
		const bodyCount = this.snake.length - 1
		for (let i = 0; i < bodyCount; i++) {
			const seg = this.snake[i + 1]
			const frame =
				i === bodyCount - 1 ? SPRITE_FRAMES.TAIL : SPRITE_FRAMES.BODY
			this.bodySprites[i].setTexture(SPRITESHEET_KEY, frame)
			this.bodySprites[i].setPosition(this.cellPx(seg.x), this.cellPy(seg.y))
			this.bodySprites[i].setVisible(true)
		}
	}

	private syncBodySprites(): void {
		const neededBodies = Math.max(0, this.snake.length - 1)

		// Add sprites if needed
		while (this.bodySprites.length < neededBodies) {
			const sprite = this.add
				.image(0, 0, SPRITESHEET_KEY, SPRITE_FRAMES.BODY)
				.setDisplaySize(this.cellSize, this.cellSize)
				.setVisible(false)
			// Ensure body is below head
			sprite.setDepth(0)
			this.bodySprites.push(sprite)
		}

		// Hide extra sprites
		for (let i = neededBodies; i < this.bodySprites.length; i++) {
			this.bodySprites[i].setVisible(false)
		}

		// Ensure head is on top
		this.headSprite.setDepth(1)
	}

	private updateFoodVisual(): void {
		// Kill previous food tweens
		if (this.foodIdleTween) {
			this.foodIdleTween.destroy()
			this.foodIdleTween = null
		}
		if (this.foodGlowTween) {
			this.foodGlowTween.destroy()
			this.foodGlowTween = null
		}

		const fx = this.cellPx(this.food.position.x)
		const fy = this.cellPy(this.food.position.y)

		this.foodSprite.setTexture(
			SPRITESHEET_KEY,
			this.getFoodFrame(this.food.type)
		)
		this.foodSprite.setPosition(fx, fy)

		// Spawn animation
		this.spawnFoodAnimation()
	}

	private spawnFoodAnimation(): void {
		const fx = this.cellPx(this.food.position.x)
		const fy = this.cellPy(this.food.position.y)

		// Scale from 0 with bounce
		this.foodSprite.setScale(0)
		this.tweens.add({
			targets: this.foodSprite,
			scaleX: this.cellSize / this.foodSprite.width,
			scaleY: this.cellSize / this.foodSprite.height,
			duration: 400,
			ease: 'Back.easeOut',
			onComplete: () => {
				// Start idle bobbing after spawn
				this.startFoodIdleAnimation()
			},
		})

		// Pulsing glow under food
		this.startFoodGlow(fx, fy)
	}

	private startFoodIdleAnimation(): void {
		const baseY = this.cellPy(this.food.position.y)

		this.foodIdleTween = this.tweens.add({
			targets: this.foodSprite,
			y: baseY - 2,
			duration: 800,
			yoyo: true,
			repeat: -1,
			ease: 'Sine.easeInOut',
		})
	}

	private startFoodGlow(fx: number, fy: number): void {
		// Use an object to animate the glow alpha
		const glowState = { alpha: 0.3 }

		const drawGlow = () => {
			this.foodGlow.clear()
			const tint = FOOD_PARTICLE_TINTS[this.food.type] || 0xffffff
			this.foodGlow.fillStyle(tint, glowState.alpha)
			this.foodGlow.fillCircle(fx, fy, this.cellSize * 0.7)
		}

		drawGlow()

		this.foodGlowTween = this.tweens.add({
			targets: glowState,
			alpha: { from: 0.15, to: 0.35 },
			duration: 600,
			yoyo: true,
			repeat: -1,
			ease: 'Sine.easeInOut',
			onUpdate: drawGlow,
		})
	}

	// ─── HUD ───────────────────────────────────────────────────

	private setupHUD(): void {
		const hudDepth = 100
		const padding = 14
		const textY = HUD_HEIGHT / 2
		const textResolution = Math.min(window.devicePixelRatio || 1, 2)
		const textStyle: Phaser.Types.GameObjects.Text.TextStyle = {
			fontFamily: '"Luckiest Guy", Arial, sans-serif',
			fontSize: '28px',
			color: '#FFFFFF',
			stroke: '#000000',
			strokeThickness: 5,
		}

		// Background bar - dark navy with accent line
		this.hudBg = this.add.graphics()
		this.hudBg.fillStyle(0x1a1a2e, 0.92)
		this.hudBg.fillRect(0, 0, this.canvasSize, this.gameOffsetY)
		// Accent line at bottom
		this.hudBg.fillStyle(0x2b7a8c, 0.5)
		this.hudBg.fillRect(0, this.gameOffsetY - 2, this.canvasSize, 2)
		this.hudBg.setDepth(hudDepth)

		// Score (left) - gold
		this.hudScoreText = this.add
			.text(padding, textY, `🪙 ${this.initialScore}`, {
				...textStyle,
				color: '#FFD700',
			})
			.setOrigin(0, 0.5)
			.setDepth(hudDepth + 1)
			.setResolution(textResolution)

		// Food eaten (center) - white
		this.hudFoodText = this.add
			.text(
				this.canvasSize / 2,
				textY,
				`🍎 ${this.initialFoodEaten}`,
				textStyle
			)
			.setOrigin(0.5, 0.5)
			.setDepth(hudDepth + 1)
			.setResolution(textResolution)

		// Boost timer (right, hidden initially) - gold
		this.hudBoostText = this.add
			.text(this.canvasSize - padding, textY, '', {
				...textStyle,
				color: '#FFD700',
			})
			.setOrigin(1, 0.5)
			.setDepth(hudDepth + 1)
			.setVisible(false)
			.setResolution(textResolution)
	}

	private updateHUD(): void {
		this.hudScoreText.setText(`🪙 ${this.initialScore + this.currentScore}`)
		this.hudFoodText.setText(`🍎 ${this.initialFoodEaten + this.foodEaten}`)
	}

	// ─── Particles ─────────────────────────────────────────────

	private setupParticles(): void {
		// Eat particles
		this.eatEmitter = this.add.particles(0, 0, TEXTURES.PARTICLE_CIRCLE, {
			speed: { min: 40, max: 100 },
			scale: { start: 0.6, end: 0 },
			lifespan: 400,
			alpha: { start: 1, end: 0 },
			emitting: false,
		})
		this.eatEmitter.setDepth(30)

		// Death particles
		this.deathEmitter = this.add.particles(0, 0, TEXTURES.PARTICLE_CIRCLE, {
			speed: { min: 60, max: 150 },
			scale: { start: 0.8, end: 0 },
			lifespan: 600,
			alpha: { start: 1, end: 0 },
			tint: COLORS.DEATH_FLASH,
			emitting: false,
		})
		this.deathEmitter.setDepth(30)

		// Diet particles (green puff)
		this.dietEmitter = this.add.particles(0, 0, TEXTURES.PARTICLE_CIRCLE, {
			speed: { min: 20, max: 60 },
			scale: { start: 0.5, end: 0 },
			lifespan: 350,
			alpha: { start: 0.8, end: 0 },
			tint: COLORS.PARTICLE_DIET,
			emitting: false,
		})
		this.dietEmitter.setDepth(30)

		// Boost sparkle emitter (along game area border)
		this.boostSparkleEmitter = this.add.particles(
			0,
			0,
			TEXTURES.PARTICLE_STAR,
			{
				emitting: false,
				speed: { min: 10, max: 30 },
				scale: { start: 0.4, end: 0 },
				lifespan: 600,
				alpha: { start: 1, end: 0 },
				tint: COLORS.BOOST_BORDER,
				emitZone: {
					type: 'edge',
					source: new Phaser.Geom.Rectangle(
						4,
						this.gameOffsetY + 4,
						this.canvasSize - 8,
						this.canvasSize - 8
					),
					quantity: 24,
				},
				frequency: 200,
			}
		)
		this.boostSparkleEmitter.setDepth(25)
	}

	private spawnEatParticles(x: number, y: number, foodType: string): void {
		const tint = FOOD_PARTICLE_TINTS[foodType] || 0xffffff
		this.eatEmitter.setParticleTint(tint)
		this.eatEmitter.emitParticleAt(x, y, 8)
	}

	private spawnDietParticles(x: number, y: number): void {
		this.dietEmitter.emitParticleAt(x, y, 5)
	}

	// ─── Score Popup ───────────────────────────────────────────

	private showScorePopup(x: number, y: number, score: number): void {
		const text = this.add
			.text(x, y, `+${score}`, {
				fontFamily: '"Luckiest Guy", Arial, sans-serif',
				fontSize: '20px',
				fontStyle: 'bold',
				color: COLORS.SCORE_POPUP,
				stroke: '#000000',
				strokeThickness: 4,
			})
			.setOrigin(0.5)
			.setDepth(40)
			.setResolution(2)

		this.tweens.add({
			targets: text,
			y: y - 30,
			alpha: 0,
			duration: 700,
			ease: 'Quad.easeOut',
			onComplete: () => text.destroy(),
		})
	}

	// ─── Input Handling ────────────────────────────────────────

	private setupInput(): void {
		this.keydownHandler = (event: KeyboardEvent) => {
			// Check pause state from registry
			const isPaused = this.registry.get('isPaused')
			if (isPaused) return

			if (event.key.startsWith('Arrow')) {
				event.preventDefault()
			}

			switch (event.key) {
				case 'ArrowUp':
					if (this.direction !== 'DOWN') {
						this.nextDirection = 'UP'
					}
					break
				case 'ArrowDown':
					if (this.direction !== 'UP') {
						this.nextDirection = 'DOWN'
					}
					break
				case 'ArrowLeft':
					if (this.direction !== 'RIGHT') {
						this.nextDirection = 'LEFT'
					}
					break
				case 'ArrowRight':
					if (this.direction !== 'LEFT') {
						this.nextDirection = 'RIGHT'
					}
					break
			}
		}

		window.addEventListener('keydown', this.keydownHandler)
	}

	// ─── Cleanup ───────────────────────────────────────────────

	private cleanup(): void {
		if (this.keydownHandler) {
			window.removeEventListener('keydown', this.keydownHandler)
		}
		this.registry.events.off('changedata-isPaused')
	}
}
